(window.webpackJsonp=window.webpackJsonp||[]).push([[933],{1759:function(n){n.exports=JSON.parse('{"content":"<blockquote>\\n<p><a href=\\"https://github.com/szimek/signature_pad\\">signature_pad</a>\u4e00\u4e2a\u57fa\u4e8eCanvas\u7684\u5e73\u6ed1\u624b\u5199\u753b\u677f\u5de5\u5177</p>\\n</blockquote>\\n<hr>\\n<h4>\u4e00\u4e9b\u4ecb\u7ecd</h4>\\n<p>\u5b9e\u73b0\u624b\u5199\u6709\u591a\u79cd\u65b9\u5f0f\u3002</p>\\n<p>\u4e00\u79cd\u6bd4\u8f83\u5bb9\u6613\u505a\u51fa\u7684\u662f\u5bf9\u9f20\u6807\u79fb\u52a8\u8f68\u8ff9\u753b\u70b9\uff0c\u518d\u5c06\u4e24\u70b9\u4e4b\u95f4\u4ee5<code>\u76f4\u7ebf</code>\u76f8\u8fde\uff0c\u6700\u540e\u518d\u8fdb\u884c\u5e73\u6ed1\u5904\u7406\uff0c\u8fd9\u79cd\u65b9\u6848\u4e0d\u9700\u8981\u4ec0\u4e48\u7b97\u6cd5\u652f\u6301\uff0c\u4f46\u540c\u6837\uff0c\u5b83\u9762\u5bf9\u4e00\u4e2a\u6027\u80fd\u548c\u7f8e\u89c2\u7684\u6289\u62e9\uff0c\u6253\u7684\u70b9\u591a\uff0c\u5bc6\u96c6\uff0c\u6027\u80fd\u76f8\u5bf9\u8f83\u4f4e\uff0c\u4f46\u66f4\u52a0\u7f8e\u89c2\uff0c\u89c6\u89c9\u4e0a\u66f4\u5e73\u6ed1\uff1b</p>\\n<p>\u6b64\u5904\u7528\u7684\u53e6\u4e00\u79cd\u65b9\u6848\uff0c\u753b\u8d1d\u585e\u5c14\u66f2\u7ebf\u3002</p>\\n<p>\u7531\u4e8e<code>canvas</code>\u6ca1\u6709\u9ed8\u8ba4\u7684\u753b\u51fa\u8d1d\u585e\u5c14\u66f2\u7ebf\u65b9\u6cd5\uff0c\u56e0\u6b64\u66f2\u7ebf\u662f\u901a\u8fc7\u4e0d\u65ad\u753b\u51fa<code>\u4e00\u4e2a\u4e2a\u70b9</code>\u5f62\u6210\u7684\uff0c\u90a3\u4e48\u95ee\u9898\u6765\u4e86\uff0c\u8fd9\u4e9b\u70b9\u8c01\u6765\u5b9a\uff1f</p>\\n<p>\u8fd9\u91cc\u4f7f\u7528\u4e86\u8d1d\u585e\u5c14\u66f2\u7ebf\u7684\u4e00\u7cfb\u5217\u7b97\u6cd5\uff0c\u5305\u62ec<code>\u6c42\u63a7\u5236\u70b9</code>\uff0c<code>\u6c42\u957f\u5ea6</code>\uff0c<code>\u8ba1\u7b97\u5f53\u524d\u70b9\u7684\u5927\u5c0f</code>\uff0c\u6700\u540e\u7528<code>canvas</code>\u753b\u51fa\u6bcf\u4e00\u4e2a\u786e\u5b9a\u4f4d\u7f6e\u7684\u70b9\u3002</p>\\n<h4>\u53c2\u6570\u53ca\u914d\u7f6e\u4ecb\u7ecd</h4>\\n<p>\u63d0\u4f9b\u7684\u53ef\u914d\u7f6e\u53c2\u6570\u5982\u4e0b</p>\\n<pre class=\\"hljs\\"><code>export interface IOptions {\\n  // \u70b9\u7684\u5927\u5c0f(\u4e0d\u662f\u7ebf\u6761)\\n  dotSize?: number | (() =&gt; number);\\n  // \u6700\u7c97\u7684\u7ebf\u6761\u5bbd\u5ea6\\n  minWidth?: number;\\n  // \u6700\u7ec6\u7684\u7ebf\u6761\u5bbd\u5ea6\\n  maxWidth?: number;\\n  // \u6700\u5c0f\u95f4\u9694\u8ddd\u79bb(\u8fd9\u4e2a\u8ddd\u79bb\u7528\u8d1d\u585e\u5c14\u66f2\u7ebf\u586b\u5145)\\n  minDistance?: number;\\n  // \u80cc\u666f\u8272\\n  backgroundColor?: string;\\n  // \u7b14\u989c\u8272\\n  penColor?: string;\\n  // \u8282\u6d41\u7684\u95f4\u9694\\n  throttle?: number;\\n  // \u5f53\u524d\u753b\u7b14\u901f\u5ea6\u7684\u8ba1\u7b97\u7387\uff0c\u9ed8\u8ba40.7\uff0c\u610f\u601d\u5c31\u662f \u5f53\u524d\u901f\u5ea6=\u5f53\u524d\u5b9e\u9645\u901f\u5ea6*0.7+\u4e0a\u4e00\u6b21\u901f\u5ea6*0.3\\n  velocityFilterWeight?: number;\\n  // \u521d\u59cb\u56de\u8c03\\n  onBegin?: (event: MouseEvent | Touch) =&gt; void;\\n  // \u7ed3\u675f\u56de\u8c03\\n  onEnd?: (event: MouseEvent | Touch) =&gt; void;\\n}\\n</code></pre>\\n<p>\u8fd9\u91cc\u8981\u6ce8\u610f\u7684\u662f\u5e76\u6ca1\u6709<code>\u7ebf\u6761\u7c97\u7ec6</code>\u8fd9\u4e2a\u9009\u9879\uff0c\u56e0\u4e3a\u8fd9\u91cc\u9762\u7684\u7c97\u7ec6\u4e0d\u7b49\u7ebf\u6761\u90fd\u662f\u901a\u8fc7\u4e00\u4e2a\u4e2a\u5927\u5c0f\u4e0d\u540c\u7684\u70b9\u6784\u9020\u800c\u6210\uff1b</p>\\n<p><code>throttle</code>\u8fd9\u4e2a\u914d\u7f6e\u53ef\u4ee5\u53c2\u8003<code>loadsh</code>\u6216\u8005<code>underscore</code>\u7684<code>_.throttle</code>\uff0c\u529f\u80fd\u4e00\u81f4\uff0c\u5c31\u662f\u4e3a\u4e86\u63d0\u9ad8\u6027\u80fd\u3002</p>\\n<h4>\u6ce8\u518c\u4e8b\u4ef6</h4>\\n<p>\u5728<code>constructor</code>\u5185\u90e8\uff0c\u9664\u4e86\u914d\u7f6e\u4f20\u5165\u7684\u53c2\u6570\u5916\uff0c\u5c31\u662f\u6ce8\u518c\u4e8b\u4ef6\u3002</p>\\n<p>\u8fd9\u91cc\u4f18\u5148\u4f7f\u7528\u4e86<a href=\\"https://developer.mozilla.org/zh-CN/docs/Web/API/PointerEvent\\">PointerEvent</a>\u89e6\u70b9\u4e8b\u4ef6\uff0c<code>PointerEvent</code>\u53ef\u4ee5\u8bf4\u662f\u89e6\u6478\u4ee5\u53ca\u70b9\u51fb\u4e8b\u4ef6\u7684\u4e00\u4e2a\u7edf\u4e00\uff0c\u5982\u679c\u8bbe\u5907\u652f\u6301\uff0c\u4e0d\u9700\u8981\u518d\u5206\u522b\u4e3a<code>mouse</code>\u548c<code>touch</code>\u5199\u4e24\u5957\u4e8b\u4ef6\u4e86\u3002</p>\\n<h4>\u72b6\u6001\u6570\u636e\u50a8\u5b58</h4>\\n<p>\u72b6\u6001\u5f00\u5173\uff1a</p>\\n<ul>\\n<li>\\n<p><code>this._mouseButtonDown</code></p>\\n<p>\u5f53\u6267\u884c<code>move</code>\u4e8b\u4ef6\u65f6\uff0c\u4f1a\u68c0\u67e5\u6b64\u72b6\u6001\uff0c\u53ea\u6709\u5728<code>true</code>\u7684\u60c5\u51b5\u4e0b\u624d\u4f1a\u6267\u884c\u3002</p>\\n</li>\\n</ul>\\n<p>\u6570\u636e\u50a8\u5b58\u5206\u4e3a2\u79cd\u683c\u5f0f\uff1a</p>\\n<ol>\\n<li>\\n<p><code>pointGroup</code></p>\\n<p>\u8fd9\u662f\u5f53\u524d\u7b14\u753b\u7684\u70b9\u7684\u4e00\u4e2a\u96c6\u5408\uff0c\u5185\u90e8\u50a8\u5b58\u4e86\u5f53\u524d\u7b14\u753b\u7684\u989c\u8272<code>color</code>\u548c\u6240\u6709\u7684\u70b9<code>points&lt;Array&gt;</code>\u3002</p>\\n</li>\\n<li>\\n<p><code>this._data</code></p>\\n<p>\u8fd9\u662f\u4e00\u4e2a\u50a8\u5b58\u6240\u6709\u7b14\u753b\u7684\u6808\uff0c\u683c\u5f0f\u4e3a<code>[pointGroup, pointGroup, ..., pointGroup]</code>\uff0c\u5f53\u9700\u8981\u6267\u884c<code>undo</code>\u7684\u65f6\u5019\uff0c\u53ea\u9700\u8981\u5220\u9664<code>this._data</code>\u4e2d\u7684\u6700\u540e\u4e00\u6761\u6570\u636e\u3002</p>\\n</li>\\n</ol>\\n<h4>\u4e8b\u4ef6\u6d41\u7a0b\u53ca\u65b9\u6cd5</h4>\\n<h5><code>mouseDown</code>\u4e8b\u4ef6</h5>\\n<p>\u5f53\u9f20\u6807(\u89e6\u70b9)\u6309\u4e0b\u65f6\uff0c\u6539\u53d8\u72b6\u6001<code>this._mouseButtonDown = true</code>\uff0c\u8c03\u7528<code>onBegin</code>\u56de\u8c03\uff0c\u521b\u5efa\u5f53\u524d\u7b14\u753b\u7684\u4e00\u4e2a\u65b0\u7684\u96c6\u5408\uff0c\u7136\u540e\u5bf9<strong>\u5f53\u524d\u70b9\u6267\u884c\u66f4\u65b0</strong>\u3002</p>\\n<h5><code>mouseMove</code>\u4e8b\u4ef6</h5>\\n<p>\u9996\u5148\u68c0\u67e5<code>this._mouseButtonDown</code>\u72b6\u6001\uff0c\u5bf9<strong>\u5f53\u524d\u70b9\u6267\u884c\u66f4\u65b0</strong>\u3002</p>\\n<h5><code>mouseUp</code>\u4e8b\u4ef6</h5>\\n<p>\u6539\u53d8\u72b6\u6001<code>this._mouseButtonDown = false;</code>\uff0c\u8c03\u7528<code>onEnd</code>\u56de\u8c03\uff0c\u5bf9<strong>\u5f53\u524d\u70b9\u6267\u884c\u66f4\u65b0</strong>\u3002</p>\\n<p>\u53ef\u4ee5\u770b\u5230\uff0c\u4e0a\u9762\u7684\u6bcf\u4e00\u4e2a\u4e8b\u4ef6\u5185\u90e8\u90fd\u8c03\u7528\u5bf9\u5f53\u524d\u70b9\u6267\u884c\u66f4\u65b0\u7684\u65b9\u6cd5\u3002</p>\\n<h5>\u70b9\u7684\u66f4\u65b0\u65b9\u6cd5<code>_strokeUpdate</code></h5>\\n<pre class=\\"hljs\\"><code>private _strokeUpdate(event: MouseEvent | Touch): <span class=\\"hljs-keyword\\">void</span> {\\n    <span class=\\"hljs-comment\\">// \u83b7\u53d6\u5f53\u524d\u89e6\u70b9\u7684\u4f4d\u7f6e</span>\\n    <span class=\\"hljs-keyword\\">const</span> x = event.clientX;\\n    <span class=\\"hljs-keyword\\">const</span> y = event.clientY;\\n\\n    <span class=\\"hljs-comment\\">// \u521b\u5efa\u70b9</span>\\n    <span class=\\"hljs-keyword\\">const</span> point = <span class=\\"hljs-keyword\\">this</span>._createPoint(x, y);\\n    <span class=\\"hljs-comment\\">// \u8c03\u51fa\u6700\u540e\u4e00\u4e2a\u70b9\u96c6</span>\\n    <span class=\\"hljs-keyword\\">const</span> lastPointGroup = <span class=\\"hljs-keyword\\">this</span>._data[<span class=\\"hljs-keyword\\">this</span>._data.length - <span class=\\"hljs-number\\">1</span>];\\n    <span class=\\"hljs-comment\\">// \u83b7\u53d6\u6700\u540e\u4e00\u4e2a\u70b9\u96c6\u7684\u70b9\u7684\u6570\u7ec4</span>\\n    <span class=\\"hljs-keyword\\">const</span> lastPoints = lastPointGroup.points;\\n    <span class=\\"hljs-comment\\">// \u5982\u679c\u5b58\u5728\u4e0a\u4e00\u4e2a\u70b9\uff0c\u83b7\u53d6\u4e0a\u4e00\u4e2a\u70b9</span>\\n    <span class=\\"hljs-keyword\\">const</span> lastPoint =\\n      lastPoints.length &gt; <span class=\\"hljs-number\\">0</span> &amp;&amp; lastPoints[lastPoints.length - <span class=\\"hljs-number\\">1</span>];\\n    <span class=\\"hljs-comment\\">// \u5224\u65ad\u4e0a\u4e00\u4e2a\u70b9\u5230\u5f53\u524d\u70b9\u662f\u5426\u592a\u8fd1(\u4e5f\u5c31\u662f\u5c0f\u4e8e\u914d\u7f6e\u7684\u6700\u5c0f\u95f4\u9694\u8ddd\u79bb)</span>\\n    <span class=\\"hljs-keyword\\">const</span> isLastPointTooClose = lastPoint\\n      ? point.distanceTo(lastPoint) &lt;= <span class=\\"hljs-keyword\\">this</span>.minDistance\\n      : <span class=\\"hljs-literal\\">false</span>;\\n    <span class=\\"hljs-comment\\">// \u8c03\u51fa\u70b9\u96c6\u7684\u989c\u8272</span>\\n    <span class=\\"hljs-keyword\\">const</span> color = lastPointGroup.color;\\n\\n    <span class=\\"hljs-comment\\">// Skip this point if it\'s too close to the previous one</span>\\n    <span class=\\"hljs-comment\\">// \u5b58\u5728\u4e0a\u4e00\u4e2a\u70b9\u4f46\u662f\u592a\u8fd1\uff0c\u8df3\u8fc7\uff0c\u5176\u4f59\u7684\u6267\u884c</span>\\n    <span class=\\"hljs-keyword\\">if</span> (!lastPoint || !(lastPoint &amp;&amp; isLastPointTooClose)) {\\n      <span class=\\"hljs-comment\\">// \u5411\u4e0a\u4e00\u6b21\u7684\u70b9\u6570\u7ec4\u4e2d\u6dfb\u52a0\u5f53\u524d\u70b9\uff0c\u5e76\u4e14\u751f\u6210\u4e00\u4e2a\u65b0\u7684\u8d1d\u585e\u5c14\u66f2\u7ebf\u5b9e\u4f8b</span>\\n      <span class=\\"hljs-comment\\">// \u5305\u62ec4\u4e2a\u70b9 \uff08\u521d\u59cb\u70b9\uff0c2\u4e2a\u63a7\u5236\u70b9\uff0c\u7ed3\u675f\u70b9\uff09</span>\\n      <span class=\\"hljs-comment\\">// \u521d\u59cb\u5bbd\u5ea6\uff0c\u6700\u7ec8\u5bbd\u5ea6</span>\\n      <span class=\\"hljs-keyword\\">const</span> curve = <span class=\\"hljs-keyword\\">this</span>._addPoint(point);\\n\\n      <span class=\\"hljs-comment\\">// \u5982\u679c\u4e0d\u5b58\u5728lastPoint\uff0c\u5373\u5f53\u524d\u70b9\u662f\u7b2c\u4e00\u4e2a\u70b9</span>\\n      <span class=\\"hljs-keyword\\">if</span> (!lastPoint) {\\n        <span class=\\"hljs-comment\\">// \u753b\u4e00\u4e2a\u70b9</span>\\n        <span class=\\"hljs-keyword\\">this</span>._drawDot({ color, point });\\n      <span class=\\"hljs-comment\\">// \u5982\u679c\u5b58\u5728lastPoint \u5e76\u4e14\u80fd\u5f62\u6210\u4e00\u4e2a\u8d1d\u585e\u5c14\u66f2\u7ebf\u5b9e\u4f8b(3\u4e2a\u70b9\u4ee5\u4e0a)</span>\\n      } <span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span> (curve) {\\n        <span class=\\"hljs-comment\\">// \u753b\u51fa\u53c2\u6570\u4e2dcurve\u5b9e\u4f8b\u4e2d\u4e24\u70b9\u4e4b\u95f4\u7684\u66f2\u7ebf</span>\\n        <span class=\\"hljs-keyword\\">this</span>._drawCurve({ color, curve });\\n      }\\n      <span class=\\"hljs-comment\\">// \u6dfb\u52a0\u5230\u5f53\u524d\u7b14\u753b\u7684\u70b9\u6570\u7ec4</span>\\n      lastPoints.push({\\n        <span class=\\"hljs-attr\\">time</span>: point.time,\\n        <span class=\\"hljs-attr\\">x</span>: point.x,\\n        <span class=\\"hljs-attr\\">y</span>: point.y,\\n      });\\n    }\\n  }\\n</code></pre>\\n<p>\u8fd9\u4e2a\u65b9\u6cd5\u524d\u9762\u5c31\u662f\u4e00\u7cfb\u5217\u5224\u65ad</p>\\n<ul>\\n<li>\\n<p>\u5224\u65ad\u662f\u5426\u662f\u7b2c\u4e00\u4e2a\u70b9</p>\\n</li>\\n<li>\\n<p>\u5224\u65ad\u662f\u5426\u80fd\u52a0\u5165\u70b9\u7684\u96c6\u5408(\u6ee1\u8db3\u70b9\u7684\u6700\u5c0f\u95f4\u9694)</p>\\n</li>\\n<li>\\n<p>\u5224\u65ad\u662f\u5426\u80fd\u753b\u51fa\u8d1d\u585e\u5c14\u66f2\u7ebf(\u6ee1\u8db3\u81f3\u5c113\u4e2a\u70b9)</p>\\n<p>\u5bf9\u4e8e\u80fd\u753b\u51fa\u8d1d\u585e\u5c14\u66f2\u7ebf\u7684\u70b9\uff0c\u6267\u884c\u7b97\u6cd5\uff0c\u6c42\u51fa<code>Besier</code>\u5b9e\u4f8b\uff0c\u5305\u62ec4\u4e2a\u70b9<code>\u521d\u59cb\u70b9</code>\uff0c<code>\u7ed3\u675f\u70b9</code>\uff0c<code>\u63a7\u5236\u70b91</code>\uff0c<code>\u63a7\u5236\u70b92</code>\u4ee5\u53ca\u5f53\u524d\u66f2\u7ebf\u4e2d\u7ebf\u6761\u7684\u7684<code>\u521d\u59cb\u5bbd\u5ea6</code>\u548c<code>\u7ed3\u675f\u5bbd\u5ea6</code>\u3002</p>\\n<p>\u5177\u4f53\u5982\u4f55\u7b97\u7684\uff0c\u8bf7\u53c2\u8003\u6e90\u7801<code>src/bezier.ts</code>\u548c<a href=\\"https://medium.com/square-corner-blog/smoother-signatures-be64515adb33\\">\u8fd9\u7bc7\u6587\u7ae0</a>\u3002</p>\\n</li>\\n</ul>\\n<p>\u5bf9\u4e8e\u80fd\u753b\u51fa\u8d1d\u585e\u5c14\u66f2\u7ebf\u7684\uff0c\u5bf9\u5df2\u7ecf\u6c42\u51fa\u7684<code>Bezier</code>\u5b9e\u4f8b\uff0c\u6267\u884c<code>this._drawCurve</code>\uff0c\u5426\u5219\u6267\u884c<code>this._drawDot</code></p>\\n<h5>\u753b\u70b9\u7684\u65b9\u6cd5<code>this._drawDot</code></h5>\\n<p>\u83b7\u53d6\u914d\u7f6e\u4e2d\u7684<code>dotSize</code>\uff0c\u6267\u884c<code>canvas</code>\u753b\u70b9\u3002</p>\\n<h5>\u753b\u7ebf\u7684\u65b9\u6cd5<code>this.__drawCurve</code></h5>\\n<ol>\\n<li>\\n<p>\u6c42\u51fa\u5f53\u524d<code>Bezier</code>\u5b9e\u4f8b<code>\u521d\u59cb\u70b9</code>\u548c<code>\u7ed3\u675f\u70b9</code>\u4e4b\u95f4\u7684\u8ddd\u79bb\uff0c\u8fd9\u4e2a\u8ddd\u79bb\u4e0d\u662f\u76f4\u7ebf\u8ddd\u79bb\uff0c\u800c\u662f\u8d1d\u585e\u5c14\u66f2\u7ebf\u8ddd\u79bb\u3002</p>\\n</li>\\n<li>\\n<p>\u5bf9\u8fd9\u4e2a\u8ddd\u79bb\u8fdb\u884c\u6269\u5c55\uff0c\u4f8b\u5982\uff0c\u8ba1\u7b97\u5f97\u5230\u8ddd\u79bb\u4e3a<code>50</code>\uff0c\u90a3\u5c31\u6269\u5c55\u4e3a<code>100</code>\u4e2a\u70b9\uff0c\u5373\u6211\u9700\u8981\u5728<code>50</code>\u8fd9\u4e2a\u8ddd\u79bb\u5185\u753b\u51fa<code>100</code>\u4e2a\u70b9\uff1b</p>\\n<p>\u8fd9\u4e48\u505a\u53ef\u4ee5\u4fdd\u8bc1\u5728\u6b63\u5e38\u6216\u8005\u7a0d\u5fae\u5feb\u901f\u7684\u4e66\u5199\u4e2d\uff0c\u4e0d\u51fa\u73b0\u65ad\u5c42\u3002</p>\\n</li>\\n<li>\\n<p>\u63a5\u7740\u53c8\u662f<a href=\\"https://medium.com/square-corner-blog/smoother-signatures-be64515adb33\\">\u7b97\u6cd5</a>\uff0c\u76ee\u7684\u662f\u6c42\u51fa\u8fd9\u4e2a\u8ddd\u79bb\u5185\u7684\u6bcf\u4e00\u4e2a\u70b9\u7684\u5927\u5c0f\uff0c\u8fd9\u662f\u4e00\u4e2a\u53d8\u5316\u503c\uff0c\u662f\u7684\u7c97\u7ec6\u53d8\u5316\u66f4\u52a0\u5e73\u6ed1\u3002</p>\\n</li>\\n<li>\\n<p>\u6700\u540e\u540c\u6837\u662f<code>canvas</code>\u753b\u70b9\u3002</p>\\n</li>\\n</ol>\\n<p>\u4ee5\u4e0a\u5c31\u662f\u6574\u4e2a\u57fa\u672c\u6d41\u7a0b\u3002</p>\\n<h4>\u603b\u7ed3</h4>\\n<p>\u9605\u8bfb\u4e00\u904d\u540e\uff0c\u8fd9\u4e2a\u5e93\u8bf4\u767d\u5c31\u662f\u57fa\u7840\u7684\u4e8b\u4ef6\u64cd\u4f5c+\u8d1d\u585e\u5c14\u66f2\u7ebf\u7b97\u6cd5\uff0c\u4f46\u662f\uff0c\u5b83\u5185\u90e8\u7684\u4ee3\u7801\u683c\u5f0f\u975e\u5e38\u6e05\u6670\uff0c<code>\u7ec6\u7c92\u5ea6+\u4ee3\u7801\u590d\u7528</code>\u4f7f\u5f97\u7ef4\u62a4\u8d77\u6765\u975e\u5e38\u65b9\u4fbf\u3002</p>\\n<p>\u540c\u65f6\u53ef\u4ee5\u5bf9\u8d1d\u585e\u5c14\u66f2\u7ebf\u6709\u4e00\u4e2a\u66f4\u6df1\u5c42\u7684\u4e86\u89e3(\u7b97\u6cd5\u8fd8\u662f\u6ca1\u6cd5\u624b\u6495\u56e7)\uff0c\u4f46\u8d77\u7801\u6709\u4e00\u4e2a\u6bd4\u8f83\u5b8c\u6574\u7684\u601d\u8def\uff1b</p>\\n<p>\u4e00\u4e9b\u53ef\u4ee5\u501f\u9274\u7684\u4e1c\u897f\uff1a</p>\\n<ul>\\n<li><a href=\\"#%E6%B3%A8%E5%86%8C%E4%BA%8B%E4%BB%B6\\">PointerEvent\u7684\u4f18\u52bf</a></li>\\n<li>canvas+\u8d1d\u585e\u5c14\u66f2\u7ebf</li>\\n<li>\u8282\u6d41<code>throttle</code>\u7684\u5199\u6cd5(\u53c2\u8003\u6e90\u7801src/throttle.ts)</li>\\n<li><a href=\\"#%E7%8A%B6%E6%80%81%E6%95%B0%E6%8D%AE%E5%82%A8%E5%AD%98\\">\u6570\u636e\u7ed3\u6784\u53ca\u5b9e\u73b0<code>undo</code>\u7684\u65b9\u6848</a></li>\\n</ul>\\n<blockquote>\\n<p>\u8d1d\u585e\u5c14\u66f2\u7ebf\u7b97\u6cd5\u8d44\u6599\uff1a</p>\\n<ul>\\n<li>https://medium.com/square-corner-blog/smoother-signatures-be64515adb33</li>\\n<li>https://www.lemoda.net/maths/bezier-length/index.html</li>\\n</ul>\\n</blockquote>\\n<hr>\\n<blockquote>\\n<p><a href=\\"https://segmentfault.com/blog/souce-code\\"><strong>\u6e90\u7801\u9605\u8bfb\u4e13\u680f</strong></a>\u5bf9\u4e00\u4e9b\u4e2d\u5c0f\u578b\u70ed\u95e8\u9879\u76ee\u8fdb\u884c\u6e90\u7801\u9605\u8bfb\u548c\u5206\u6790\uff0c\u5bf9\u5176\u6574\u4f53\u505a\u51fa\u5bfc\u56fe\uff0c\u4ee5\u4fbf\u5feb\u901f\u4e86\u89e3\u5185\u90e8\u5173\u7cfb\u53ca\u6267\u884c\u987a\u5e8f\u3002\\n\u5f53\u524d\u6e90\u7801(\u5e26\u6ce8\u91ca)\uff0c\u4ee5\u53ca\u66f4\u591a\u6e90\u7801\u9605\u8bfb\u5185\u5bb9\uff1a<a href=\\"https://github.com/stonehank/sourcecode-analysis\\">https://github.com/stonehank/sourcecode-analysis</a>\uff0c\u6b22\u8fce<code>fork</code>\uff0c\u6c42:star:</p>\\n</blockquote>\\n"}')}}]);